@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="LoadShipments">
            <span class="@(loading ? "spinner-border spinner-border-sm me-1" : "")"></span>
            Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is not null)
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                        <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool loading = true;

    private IEnumerable<Shipment> FilteredShipments => shipments?
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter)
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync();
        loading = false;
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchByTracking" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
    <div class="col-md-3">
        <button class="btn btn-outline-secondary" @onclick="LoadMyShipments">
            View All My Shipments
        </button>
    </div>
</div>

@if (searchedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Shipment @searchedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@searchedShipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@searchedShipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@searchedShipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(searchedShipment.Status) fs-6">@searchedShipment.Status</span></dd>
                        <dt>Shipped Date</dt>
                        <dd>@searchedShipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold text-primary">@searchedShipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>
            @{
                var progress = GetDeliveryProgress(searchedShipment);
            }
            <div class="progress mt-3" style="height: 25px;">
                <div class="progress-bar @GetProgressBarClass(searchedShipment.Status)"
                     role="progressbar" style="width: @progress%"
                     aria-valuenow="@progress" aria-valuemin="0" aria-valuemax="100">
                    @searchedShipment.Status
                </div>
            </div>
        </div>
    </div>
}
else if (notFound)
{
    <div class="alert alert-warning">
        No shipment found with tracking number "<strong>@lastSearched</strong>".
    </div>
}

@if (myShipments is not null)
{
    <h3>My Shipments</h3>
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h6 class="card-title">@shipment.TrackingNumber</h6>
                        <p class="card-text text-muted">@shipment.Description</p>
                        <p class="mb-1"><strong>To:</strong> @shipment.Destination</p>
                        <p class="mb-1">
                            <strong>Status:</strong>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                        </p>
                        <p class="mb-0"><strong>Est. Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private Shipment? searchedShipment;
    private List<Shipment>? myShipments;
    private bool searching;
    private bool notFound;
    private string lastSearched = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchByTracking();
        }
    }

    private async Task SearchByTracking()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        notFound = false;
        searchedShipment = null;
        lastSearched = trackingNumber.Trim();

        searchedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        notFound = searchedShipment is null;
        searching = false;
    }

    private async Task LoadMyShipments()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name ?? string.Empty;
        myShipments = await ShipmentService.GetShipmentsByCustomerAsync(email);
    }

    private static int GetDeliveryProgress(Shipment shipment) => shipment.Status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => ""
    };
}

