using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await httpClient.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", status);
    }
}
```

### 4. Create the server-side implementation using EF Core
Create `/tmp/sv-e08c791593e44eee8bcbb2693653da51/ShipmentTracker/ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext dbContext) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await dbContext.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await dbContext.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await dbContext.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .OrderByDescending(s => s.ShippedDate)
            .ToListAsync();
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await dbContext.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = status;
            await dbContext.SaveChangesAsync();
        }
    }
}
```

